messages.content:
Analyze the following JSON PRD and design resource access interfaces.

JSON PRD:
```json
{
  "metadata": {
    "project_name": "Simple Book Library",
    "project_id": "com.example.booklibrary",
    "version": "1.0.0"
  },
  "functional_requirements": [
    {
      "fr_id": "FR-001",
      "title": "Add Book",
      "description": "User can add a new book with title and author. Each book gets a unique ID and default status 'available'.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-002",
      "title": "List Books",
      "description": "User can list all books, optionally filtered by status (available/borrowed/all). Output includes ID, title, author, status.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-003",
      "title": "Borrow Book",
      "description": "User can borrow a book by ID. Checks that book exists and is available, then changes status to 'borrowed'.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-004",
      "title": "Return Book",
      "description": "User can return a book by ID. Checks that book exists and is borrowed, then changes status to 'available'.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-005",
      "title": "Remove Book",
      "description": "User can delete a book by ID. Checks that book exists and is not currently borrowed.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    }
  ],
  "non_functional_requirements": [
    {
      "nfr_id": "NFR-001",
      "category": "reliability",
      "description": "All five operations must execute correctly with proper state transitions."
    },
    {
      "nfr_id": "NFR-002",
      "category": "usability",
      "description": "Error handling must be comprehensive: book not found, duplicate borrow, etc."
    }
  ],
  "acceptance_criteria": [
    {
      "ac_id": "AC-001",
      "description": "Add book: book is added with unique ID and status 'available'.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-002",
      "description": "List books: returns correct list with optional status filter.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002"
      ]
    },
    {
      "ac_id": "AC-003",
      "description": "Borrow book: changes status from 'available' to 'borrowed'.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-003"
      ]
    },
    {
      "ac_id": "AC-004",
      "description": "Return book: changes status from 'borrowed' to 'available'.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-004"
      ]
    },
    {
      "ac_id": "AC-005",
      "description": "Remove book: deletes book only if not borrowed.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-006",
      "description": "Error handling: appropriate error messages for invalid operations.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001",
        "FR-002",
        "FR-003",
        "FR-004",
        "FR-005"
      ]
    }
  ],
  "technical_constraints": {
    "storage": {
      "type": "memory",
      "details": "No persistence; data lost on session end."
    },
    "concurrency": {
      "model": "single-user",
      "auth_required": false
    },
    "ui": {
      "type": "api"
    },
    "language": "Python"
  },
  "glossary": {
    "book": "A record containing title, author, unique ID, and borrow status.",
    "available": "Status indicating the book is not borrowed.",
    "borrowed": "Status indicating the book is currently borrowed."
  },
  "global_state_sources": [
    {
      "source_id": "books",
      "type": "dict",
      "description": "Stores all books with book_id as key.",
      "initial_state": {},
      "item_schema": {
        "book_id": "integer",
        "title": "string",
        "author": "string",
        "status": "string (available/borrowed)"
      }
    },
    {
      "source_id": "next_id",
      "type": "dict",
      "description": "Counter for generating unique book IDs.",
      "initial_state": {
        "next_id": 1
      },
      "item_schema": {
        "next_id": "integer"
      }
    }
  ],
  "input_spec": {
    "format": "json",
    "description": "Input is a JSON object with command and book_data fields.",
    "schema": {
      "command": "string (add|list|borrow|return|remove)",
      "book_data": {
        "title": "string (required for add)",
        "author": "string (required for add)",
        "book_id": "integer (required for borrow/return/remove)",
        "status_filter": "string (optional for list: available/borrowed/all)"
      }
    },
    "examples": [
      {
        "command": "add",
        "book_data": {
          "title": "Python编程",
          "author": "John"
        }
      },
      {
        "command": "list",
        "book_data": {
          "status_filter": "all"
        }
      },
      {
        "command": "borrow",
        "book_data": {
          "book_id": 1
        }
      },
      {
        "command": "return",
        "book_data": {
          "book_id": 1
        }
      },
      {
        "command": "remove",
        "book_data": {
          "book_id": 1
        }
      }
    ]
  },
  "output_spec": {
    "format": "json",
    "description": "Output is a JSON object with success, message, and data fields.",
    "schema": {
      "success": "boolean",
      "message": "string",
      "data": "object (varies by operation)"
    },
    "examples": [
      {
        "success": true,
        "message": "书籍添加成功，ID=1",
        "data": {
          "book_id": 1
        }
      },
      {
        "success": true,
        "message": "共1本书",
        "data": {
          "books": [
            {
              "id": 1,
              "title": "Python编程",
              "author": "John",
              "status": "available"
            }
          ]
        }
      },
      {
        "success": true,
        "message": "书籍借出成功",
        "data": {
          "book_id": 1
        }
      },
      {
        "success": true,
        "message": "书籍归还成功",
        "data": {
          "book_id": 1
        }
      },
      {
        "success": true,
        "message": "书籍删除成功",
        "data": {
          "book_id": 1
        }
      }
    ]
  }
}
```

Remember:
- Choose storage model from: dict, list, in_memory_table
- Choose operations from: get, list, create, update, delete, exists
- Do NOT create business action interfaces like pay_order or ship_order
- Create only low-level CRUD interfaces
- Every resource needs at least a get interface
